command:
mkdir -p space && printf 'metrics:
  - {id: m1, dimension: satisfaction}
  - {id: m2, dimension: performance}
  - {id: m3, dimension: activity}
  - {id: m4, dimension: collaboration}
  - {id: m5, dimension: efficiency_and_flow}
' > space/metrics.yaml && printf 'dimensions:
  satisfaction: {opt_in: true, enabled: true}
  performance: {enabled: true}
  activity: {opt_in: true, enabled: true}
  collaboration: {opt_in: true, enabled: true}
  efficiency_and_flow: {enabled: true}
share: never
' > space/config.yaml && bash "$CLAUDE_PLUGIN_ROOT/commands/space-report.sh" --metrics space/metrics.yaml --config space/config.yaml 2>out.txt && grep -q '## Satisfaction' out.txt && grep -q '## Performance' out.txt && grep -q '## Activity' out.txt && grep -q '## Collaboration' out.txt && grep -q '## Efficiency' out.txt && echo ok 1>&2
